# src/adapters/bedrock.py
import boto3, json
from genai_sdk.core.protocol import LLMProvider, CompletionRequest, CompletionResponse

class BedrockAdapter(LLMProvider):
    name    = "bedrock"
    version = "1.0.0"

    def __init__(self, region: str, model_id: str):
        self._client   = boto3.client("bedrock-runtime", region_name=region)
        self._model_id = model_id

    def supports_model(self, model_id: str) -> bool:
        return model_id.startswith("anthropic.")

    def count_tokens(self, text: str) -> int:
        # Bedrock doesn't expose a token count API; use character-based estimate
        return len(text) // 4

    def complete(self, req: CompletionRequest) -> CompletionResponse:
        payload = {
            "anthropic_version": "bedrock-2023-05-31",
            "max_tokens": req.max_tokens or 1024,
            "messages": [{"role": "user", "content": req.user}],
        }
        if req.system:
            payload["system"] = req.system

        response = self._client.invoke_model(
            modelId=self._model_id,
            body=json.dumps(payload),
            contentType="application/json",
            accept="application/json",
        )
        body = json.loads(response["body"].read())
        return CompletionResponse(
            text=body["content"][0]["text"],
            input_tokens=body["usage"]["input_tokens"],
            output_tokens=body["usage"]["output_tokens"],
            model=self._model_id,
            provider=self.name,
        )
